FUNCTION_BLOCK FB_MainCounter
VAR_OUTPUT
    q_nCycles : DINT;
END_VAR
q_nCycles := q_nCycles + 1;
END_FUNCTION_BLOCK

PROGRAM MAIN
VAR
    nCycles : DINT;
END_VAR
// Production comments do not make this an FB_TestRunner m_udiRegisterTest(fake) registration program.
nCycles := nCycles + 1;
END_PROGRAM

FUNCTION_BLOCK FB_Test_ProductionMain EXTENDS FB_TestCaseBase
VAR
    fbCut : FB_MainCounter;
END_VAR
METHOD PUBLIC m_xExecute : BOOL
VAR_INPUT
    i_xTrigger : BOOL;
END_VAR
IF i_xTrigger THEN
    _sTestCaseName := 'production MAIN remains compiled';
    _eState := eTestState_Running;
    _eExecuteState := eTestState_Running;
    fbCut();
    m_xAssertEqualDint(1, fbCut.q_nCycles, 'candidate FB executes while MAIN remains compiled');
    _eState := eTestState_Passed;
    _eExecuteState := eTestState_Passed;
    _xPhaseBusy := FALSE;
END_IF
m_xExecute := TRUE;
END_METHOD
END_FUNCTION_BLOCK
